    id: Optional[int] = None
    isoutgoing: Optional[bool] = None
    operation: Optional[str] = None
    type: Optional[str] = None
    msid: Optional[int] = None
    request_body: Optional[str] = None
    datelogged: Optional[str] = None
    resultcode: Optional[int] = None
    response_body: Optional[str] = None
    url: Optional[str] = None
    details_id: Optional[int] = None
    request_headers: Optional[str] = None
    response_headers: Optional[str] = None
    trace: Optional[List[Trace]] = None
    _retrywebhook: Optional[bool] = None
    _retry_webhook_token: Optional[str] = None
    preserve: Optional[bool] = None
    hastrace: Optional[bool] = None
    format_as_xml: Optional[bool] = None
    module_name: Optional[str] = None
    _warning: Optional[str] = None

    @classmethod
    def from_dict(cls, data: Dict[str, Any]) -> 'IntegrationRequest':
        if data is None:
            return None
        return cls(**{
            'id': data.get('id'),
            'isoutgoing': data.get('isoutgoing'),
            'operation': data.get('operation'),
            'type': data.get('type'),
            'msid': data.get('msid'),
            'request_body': data.get('request_body'),
            'datelogged': data.get('datelogged'),
            'resultcode': data.get('resultcode'),
            'response_body': data.get('response_body'),
            'url': data.get('url'),
            'details_id': data.get('details_id'),
            'request_headers': data.get('request_headers'),
            'response_headers': data.get('response_headers'),
            'trace': data.get('trace'),
            '_retrywebhook': data.get('_retrywebhook'),
            '_retry_webhook_token': data.get('_retry_webhook_token'),
            'preserve': data.get('preserve'),
            'hastrace': data.get('hastrace'),
            'format_as_xml': data.get('format_as_xml'),
            'module_name': data.get('module_name'),
            '_warning': data.get('_warning'),
        })


